+    fs.writeFileSync(
+      authPath,
+      `${JSON.stringify(
+        {
+          version: 1,
+          profiles: {
+            "anthropic:claude-cli": {
+              type: "oauth",
+              provider: "claude-cli",
+              access: "token-a",
