+    expect(next.auth?.order?.anthropic).toEqual(["anthropic:user@example.com"]);
+    expect(next.auth?.order?.["claude-cli"]).toBeUndefined();
+    expect(next.agents?.defaults?.model).toEqual({
+      primary: "anthropic/claude-sonnet-4-6",
