+      "utf8",
+    );
+
+    const next = await maybeRepairRemovedAnthropicClaudeCliState(
+      {
+        auth: {
+          profiles: {
+            "anthropic:claude-cli": {
+              provider: "claude-cli",
+              mode: "oauth",
+            },
+            "anthropic:default": {
+              provider: "anthropic",
+              mode: "api_key",
